mapper.select:
SELECT id, user_id, username, login_type, login_ip, login_location, user_agent, login_status, login_message, login_time FROM audit_user_login_log
AND user_id = #{dto.userId}
AND username LIKE CONCAT('%', #{dto.username}, '%')
AND login_type = #{dto.loginType}
AND login_ip LIKE CONCAT('%', #{dto.loginIp}, '%')
AND login_status = #{dto.loginStatus}
AND login_time >= #{dto.loginTimeStart}
AND login_time <= #{dto.loginTimeEnd}
ORDER BY login_time DESC
